A minimal guide to requests, authentication, and API testing.

4 min read
Just now

--

POSTMANPostman is a popular API development and testing tool used by developers to build, test, document, and debug APIs without writing a full application.

• Send API requests

• Test APIs

• Inspect responses

• Automate testing
Go to https://www.postman.com/ and sign up/sign in. Then download the Postman app on your computer.
Press enter or click to view image in full size

Postman UI.A workspace is a shared environment where you organize and collaborate on your APIs, collections, environments, and other Postman resources for a project.
I already have a workspace created by default at the beginning: John Doe's Workspace.
A collection is an organized group of related API requests, along with optional tests, documentation, variables, and authentication settings. Think of it as a folder.
I created a new collection: Collection1.
Now, let’s send a request. We will use the free public Pokémon API:
GET https://pokeapi.co/api/v2/pokemon/dittoPress enter or click to view image in full size

GET request.The HTTP request methods:

• GET: Retrieves data from the server without changing anything.

• POST: Creates a new resource on the server using the data you provide.

• PUT: Replaces an existing resource entirely with the new data you send.

• PATCH: Updates only the specified parts of an existing resource.

• DELETE: Removes a resource from the server.

• HEAD: Retrieves only the response headers without returning the response body.

• OPTIONS: Returns the HTTP methods and communication options that the server supports for a resource.
In Postman, the Key and Value columns let you send additional information with your request.
Press enter or click to view image in full size

When you add:

• limit — 5 (return only 5 Pokemon)

• offset — 0 (start from the beginning)
Postman creates:
https://pokeapi.co/api/v2/pokemon?limit=5&offset=0To test others, create a Python file locally:
import json
import uuid
from http.server import BaseHTTPRequestHandler, HTTPServerusers = {}
tokens = {}
books = [
{"id": 1, "title": "Clean Code", "author": "Robert C. Martin"},
{"id": 2, "title": "The Pragmatic Programmer", "author": "Andrew Hunt"},
]
class SimpleServer(BaseHTTPRequestHandler):
def send_json(self, status_code, data):
self.send_response(status_code)
self.send_header("Content-Type", "application/json")
self.end_headers()
self.wfile.write(json.dumps(data).encode())
def read_json_body(self):
content_length = int(self.headers.get("Content-Length", 0))
body = self.rfile.read(content_length)
return json.loads(body)
def get_current_user(self):
auth_header = self.headers.get("Authorization")
if not auth_header or not auth_header.startswith("Bearer "):
return None
token = auth_header.replace("Bearer ", "")
return tokens.get(token)
def do_POST(self):
if self.path == "/signup":
data = self.read_json_body()
username = data.get("username")
password = data.get("password")
if not username or not password:
return self.send_json(
400, {"error": "username and password are required"}
)
if username in users:
return self.send_json(409, {"error": "user already exists"})
users[username] = password
return self.send_json(
201, {"message": "User created successfully", "username": username}
)
if self.path == "/login":
data = self.read_json_body()
username = data.get("username")
password = data.get("password")
if users.get(username) != password:
return self.send_json(401, {"error": "invalid username or password"})
token = str(uuid.uuid4())
tokens[token] = username
return self.send_json(200, {"message": "Login successful", "token": token})
if self.path == "/books":
current_user = self.get_current_user()
if not current_user:
return self.send_json(401, {"error": "Unauthorized"})
data = self.read_json_body()
new_book = {
"id": len(books) + 1,
"title": data.get("title"),
"author": data.get("author"),
}
books.append(new_book)
return self.send_json(
201, {"message": "Book created successfully", "book": new_book}
)
return self.send_json(404, {"error": "Not found"})
def do_GET(self):
current_user = self.get_current_user()
if not current_user:
return self.send_json(401, {"error": "Unauthorized"})
if self.path == "/books":
return self.send_json(200, {"books": books})
if self.path.startswith("/books/"):
try:
book_id = int(self.path.split("/")[-1])
except ValueError:
return self.send_json(400, {"error": "Invalid book ID"})
book = next((book for book in books if book["id"] == book_id), None)
if not book:
return self.send_json(404, {"error": "Book not found"})
return self.send_json(200, {"book": book})
return self.send_json(404, {"error": "Not found"})
server = HTTPServer(("localhost", 8000), SimpleServer)
print("Server running at http://localhost:8000")
server.serve_forever()
Run the server:
python server.py
After logging in, your server returns something like:
